<template>
    <section class="container mt-5">
        <div v-if="success" class="alert alert-success">
            <h4 class="alert-heading">{{ $t('Admin consent completed') }}</h4>
            <p>{{ $t('We have stored your tenant ID. You can now complete the Office 365 email source configuration.') }}</p>
            <hr />
            <button class="btn btn-primary" @click="goBack">
                {{ $t('Return to Ticket Channel Configuration') }}
            </button>
        </div>
        <div v-else class="alert alert-danger">
            <h4 class="alert-heading">{{ $t('Admin consent failed') }}</h4>
            <p>{{ errorMessage }}</p>
            <button class="btn btn-secondary" @click="goBack">
                {{ $t('Back') }}
            </button>
        </div>
    </section>
</template>

<script>
export default {
    name: "Office365ConsentCallback",
    data() {
        return {
            success: false,
            errorMessage: ''
        };
    },
    created() {
        var q = this.$route.query;
        var adminConsent = (q.admin_consent || '').toString().toLowerCase() === 'true';
        var tenant = q.tenant || q.tid || '';

        if (!adminConsent || !tenant) {
            this.success = false;
            this.errorMessage = q.error_description || this.$t('Admin did not grant consent or tenant id was not provided.');
            return;
        }

        try {
            sessionStorage.setItem('office365_graph_tenant_id', tenant);
            sessionStorage.setItem('office365_consent_granted', 'true');
        } catch (e) {
            // ignore storage errors
        }
        this.success = true;
    },
    methods: {
        goBack() {
            this.$router.push("/Ticketing/ChannelConfigurationListing");
        }
    }
};
</script>

